function insertion(arr)
{
  for (j = 1; j &lt;= (arr.length - 1); j++)
  {
    let temp = arr[j]
    let i = j
    while (i &gt;= 1 &amp;&amp; temp &lt; arr[i - 1])
    {
      arr[i] = arr[i - 1]
      i--
    }
    arr[i] = temp
  }
  return arr
}
